SELECT ,
       c.community_no, c.building_name, c.building_address, c.city
FROM barrier_gate bg
LEFT JOIN community c ON bg.community_id = c.id


        AND bg.gate_no LIKE CONCAT('%', #{gateNo}, '%')


        AND bg.community_id = #{communityId}


        AND bg.device_no LIKE CONCAT('%', #{deviceNo}, '%')


        AND bg.device_position = #{devicePosition}


        AND bg.screen_position = #{screenPosition}


        AND bg.lightbox_direction = #{lightboxDirection}


ORDER BY bg.id DESC

SELECT COUNT(*)
FROM barrier_gate bg


        AND bg.gate_no LIKE CONCAT('%', #{gateNo}, '%')


        AND bg.community_id = #{communityId}


        AND bg.device_no LIKE CONCAT('%', #{deviceNo}, '%')


        AND bg.device_position = #{devicePosition}


        AND bg.screen_position = #{screenPosition}


        AND bg.lightbox_direction = #{lightboxDirection}

