mapper.select:
SELECT , c.community_no, c.building_name, c.building_address, c.city, c.coord_lat, c.coord_lng FROM barrier_gate bg LEFT JOIN community c ON bg.community_id = c.id WHERE NOT EXISTS ( SELECT 1 FROM plan_barrier pb WHERE pb.barrier_gate_id = bg.id AND pb.release_status IN (2, 3, 4) -- 锁位、待刊发、刊发中 AND ( (pb.release_date_begin <= #{endDate} AND pb.release_date_end >= #{beginDate}) ) )
AND c.city = #{city}
AND bg.community_id = #{communityId}
ORDER BY bg.id
LIMIT #{limit}
